fn solve(points: Vec<Vec<i64>>) -> i64 {
    const MOD: i64 = 1_000_000_007;

    let mut y_count = std::collections::HashMap::new();
    let mut y_points = std::collections::HashMap::new();

    for point in &points {
        let y = point[1];
        *y_count.entry(y).or_insert(0) += 1;
        y_points.entry(y).or_insert_with(Vec::new).push(point[0]);
    }

    let mut result = 0;

    for y in y_points.keys() {
        let xs = &y_points[y];
        let n = xs.len();

        for i in 0..n {
            for j in i + 1..n {
                let x1 = xs[i];
                let x2 = xs[j];

                for other_y in y_count.keys() {
                    if *other_y == y {
                        continue;
                    }
                    if y_points[other_y].contains(&x1) && y_points[other_y].contains(&x2) {
                        result += 1;
                        result %= MOD;
                    }
                }
            }
        }
    }

    result % MOD
}
